record.field:
# Configuración generada para {{ instance.name }} # {{ generated_at }}
[options] ; Conexión a base de datos db_host = db db_port = 5432 db_user = {{ db_user | default('odoo') }} db_password = {{ db_password }} db_name = {{ db_name | default(instance.subdomain or instance.code, true) }}
; Rutas data_dir = /var/lib/odoo addons_path = /usr/lib/python3/dist-packages/odoo/addons{% if REPO_SUBDIRS %}{% for dir in REPO_SUBDIRS %},/mnt/extra-addons/{{ dir }}{% endfor %}{% else %},/mnt/extra-addons{% endif %}
; Servidor HTTP http_port = 8069 http_interface = 0.0.0.0 gevent_port = 8072 proxy_mode = True
; Workers (ajustar según recursos del servidor) ; >=1 (prefork): un proceso gevent sirve el websocket en gevent_port (8072). ; 0 (threaded): el websocket /websocket se sirve en el puerto HTTP (8069), sin ; proceso gevent. El routing de Traefik para /websocket se ajusta solo según ; este valor. workers = {{ workers | default('2') }} max_cron_threads = 1
; Límites de recursos limit_memory_hard = 2684354560 limit_memory_soft = 2147483648 limit_request = 8192 limit_time_cpu = 600 limit_time_real = 1200
; Logging log_level = warn log_handler = :WARNING
; Seguridad list_db = False admin_passwd = {{ admin_passwd }}
